const item = $input.first().json;
const texto = item.fragmento || item.snippet || item.retazo || item.subject || item.Asunto || '';

// El fragmento tiene forma: "...para ver las imágenes galaktiturkos camisas 3.pdf enviado a..."
// Buscamos la palabra/s justo ANTES de "NombreArchivo.ext"
// Estrategia: encontrar patrón NOMBRE.pdf y tomar la(s) palabra(s) inmediatamente antes
let equipo = '';

// Busca: (una-o-dos-palabras) ESPACIO (palabra) PUNTO (ext)
// Ejemplo: "galaktiturkos camisas 3.pdf" → captura "galaktiturkos"
const matchPDF = texto.match(/(\b[a-záéíóúñü][a-záéíóúñü0-9]+)(?:\s+[\w]+)*\s+[\w-]+\.(?:pdf|cdr|ai|eps|jpg|png|zip)/i);
if (matchPDF) {
  // matchPDF[0] = "galaktiturkos camisas 3.pdf"
  // Quitamos la extensión y separamos por espacios
  const partes = matchPDF[0].replace(/\s+[\w-]+\.(?:pdf|cdr|ai|eps|jpg|png|zip)$/i, '').trim().split(/\s+/);
  // La primera parte es el nombre del equipo
  equipo = partes[0];
}

// Fallback: buscar justo antes de tipo de prenda
if (!equipo) {
  const prendas = ['camisas','camisetas','pantalon','pantaloneta','uniforme','conjunto','portero','buso','chaqueta'];
  for (const prenda of prendas) {
    const m = texto.match(new RegExp('(\\b[a-záéíóúñü][a-záéíóúñü0-9]+)\\s+' + prenda, 'i'));
    if (m) { equipo = m[1].trim(); break; }
  }
}

return [{ json: { equipo, textoOriginal: texto } }];

